 24→function projectReducer(state, action) {
 25→  switch (action.type) {
 26→    case 'PROJECT_NEW':
 27→      return {
 28→        project: action.project,
 29→        isDirty: false,
 30→        lastSavedAt: null,
 31→      };
 32→
 33→    case 'PROJECT_LOAD':
 34→      return {
 35→        project: action.project,
 36→        isDirty: false,
 37→        lastSavedAt: action.savedAt || null,
 38→      };
 39→
 40→    case 'PROJECT_SET_NAME':
 41→      return {
 42→        ...state,
 43→        isDirty: true,
 44→        project: {
 45→          ...state.project,
 46→          name: action.name,
 47→          updatedAt: new Date().toISOString(),
 48→        },
 49→      };
 50→
 51→    case 'WALL_ADD':
 52→      return updateFloor(state, action.floorId, f => ({
 53→        ...f,
 54→        walls: [...f.walls, action.wall],
 55→      }));
 56→
 57→    case 'WALL_UPDATE':
 58→      return updateFloor(state, action.floorId, f => ({
 59→        ...f,
 60→        walls: f.walls.map(w => w.id === action.wall.id ? { ...w, ...action.wall } : w),
 61→      }));
 62→
 63→    case 'WALL_DELETE': {
 64→      const wallId = action.wallId;
 65→      return updateFloor(state, action.floorId, f => ({
 66→        ...f,
 67→        walls: f.walls.filter(w => w.id !== wallId),
 68→        doors: f.doors.filter(d => d.wallId !== wallId),
 69→        windows: f.windows.filter(w => w.wallId !== wallId),
 70→      }));
 71→    }
 72→
 73→    case 'DOOR_ADD':
 74→      return updateFloor(state, action.floorId, f => ({
 75→        ...f,
 76→        doors: [...f.doors, action.door],
 77→      }));
 78→
 79→    case 'DOOR_UPDATE':
 80→      return updateFloor(state, action.floorId, f => ({
 81→        ...f,
 82→        doors: f.doors.map(d => d.id === action.door.id ? { ...d, ...action.door } : d),
 83→      }));
 84→
 85→    case 'DOOR_DELETE':
 86→      return updateFloor(state, action.floorId, f => ({
 87→        ...f,
 88→        doors: f.doors.filter(d => d.id !== action.doorId),
 89→      }));
 90→
 91→    case 'WINDOW_ADD':
 92→      return updateFloor(state, action.floorId, f => ({
 93→        ...f,
 94→        windows: [...f.windows, action.window],
 95→      }));
 96→
 97→    case 'WINDOW_UPDATE':
 98→      return updateFloor(state, action.floorId, f => ({
 99→        ...f,
100→        windows: f.windows.map(w => w.id === action.window.id ? { ...w, ...action.window } : w),
101→      }));
102→
103→    case 'WINDOW_DELETE':
104→      return updateFloor(state, action.floorId, f => ({
105→        ...f,
106→        windows: f.windows.filter(w => w.id !== action.windowId),
107→      }));
108→
109→    case 'ROOM_ADD':
110→      return updateFloor(state, action.floorId, f => ({
111→        ...f,
112→        rooms: [...f.rooms, action.room],
113→      }));
114→
115→    case 'ROOM_UPDATE':
116→      return updateFloor(state, action.floorId, f => ({
117→        ...f,
118→        rooms: f.rooms.map(r => r.id === action.room.id ? { ...r, ...action.room } : r),
119→      }));
120→
121→    case 'ROOM_DELETE':
122→      return updateFloor(state, action.floorId, f => ({
123→        ...f,
124→        rooms: f.rooms.filter(r => r.id !== action.roomId),
125→      }));
126→
127→    case 'MARK_SAVED':
128→      return {
129→        ...state,
130→        isDirty: false,
131→        lastSavedAt: new Date().toISOString(),
132→      };
133→
134→    default:
135→      return state;
136→  }
137→}
